mapper.select:
SELECT p.*, c.name AS category_name FROM mall_product p LEFT JOIN mall_category c ON p.category_id = c.id
AND p.name LIKE CONCAT('%', #{name}, '%')
AND p.category_id = #{categoryId}
AND p.status = #{status}
ORDER BY p.sort ASC, p.create_time DESC

mapper.update:
UPDATE mall_product
name = #{name}, category_id = #{categoryId}, main_image = #{mainImage}, images = #{images}, description = #{description}, price = #{price}, original_price = #{originalPrice}, stock = #{stock}, sales = #{sales}, status = #{status}, sort = #{sort},
WHERE id = #{id}
